; String comparison function
; rdi: string1, rsi: string2
; returns: rax (0 if equal, non-zero if different)
string_compare:
    push rbp
    mov rbp, rsp
    push rbx
    push rcx

    mov rbx, rdi
    mov rcx, rsi

compare_loop:
    mov al, [rbx]
    mov ah, [rcx]
    cmp al, ah
    jne compare_different
    cmp al, 0
    je compare_equal
    inc rbx
    inc rcx
    jmp compare_loop

compare_equal:
    xor rax, rax
    jmp compare_done

compare_different:
    mov rax, 1

compare_done:
    pop rcx
    pop rbx
    pop rbp
    ret

; String length function
